2409	% =========================================================================
2410	% ThangTQ23_128T128R_Rel19  —  Mode B, all ranks 1-4  (factored greedy search)
2411	% TS 38.214 §5.2.2.2.1a, Table 5.2.2.2.1a-7
2412	%
2413	% Each layer selects its beam independently:
2414	%   i1,1 = [q1 q2]  shared fractional DFT offset (O1×O2 = 16 combos)
2415	%   i1,2,l ∈ {0,...,N1N2-1}  per-layer beam index  (greedy from SVD)
2416	%   c_l  ∈ {0,1,2,3}  per-layer co-phase  (exhaustive 4^v, max 256)
2417	%
2418	% Returns: W          [Pcsirs × nLayers] precoding matrix
2419	%          pmiModeB   struct: .q1 .q2 .n_idx [1×v] .c_idx [1×v]  (0-based)
2420	%          sinrOut    [nLayers × 1] ZF SINR per layer (linear)
2421	% =========================================================================
2422	function [W, pmiModeB, sinrOut] = getPMIType1SinglePanelR19CodebookModeB(Hcsirs, reportConfig, nLayers, nVar, Pcsirs, subbandInfo, csirsIndBWP_k)
2423	% Hcsirs: [nRx × Pcsirs × nRE] (permuted in caller, averaged here to wideband)
2424	%
2425	% Phase 2: per-subband co-phase optimisation.
2426	%   Stage 1+2 (wideband): find best (q1,q2,n_idx) via capacity on H_wb.
2427	%   Stage 3   (subband):  for each subband, pick co-phase c_l for each layer
2428	%                         that maximises capacity on H_sb (subband mean channel).
2429	%
2430	% Outputs:
2431	%   W        [Pcsirs × nLayers × numSubbands]  per-subband precoder
2432	%   pmiModeB struct with fields:
2433	%              .q1, .q2         wideband DFT offset (0-based)
2434	%              .n_idx           wideband beam index per layer (0-based, [1×nLayers])
2435	%              .c_idx_sb        per-subband co-phase [nLayers × numSubbands] (0-based)
2436	%   sinrOut  [numSubbands × nLayers]  per-subband ZF SINR (linear)
2437	
2438	    panelDimensions = reportConfig.PanelDimensions;
2439	    N1 = panelDimensions(2);  N2 = panelDimensions(3);
2440	    panelConfigs = reportConfig.Tables.SinglePanelConfigurations;
2441	    configIdx    = panelConfigs{:,2} == [N1 N2];
2442	    OverSamplingFactors = panelConfigs{all(configIdx,2),3};
2443	    O1 = OverSamplingFactors(1);  O2 = OverSamplingFactors(2);
2444	
2445	    phi   = @(x) exp(1i*pi*x/2);
2446	    q_len = O1*O2;
2447	    n_len = N1*N2;
2448	
2449	    % Wideband channel: average over RE dimension → [nRx × Pcsirs]
2450	    H_wb = mean(Hcsirs, 3);   % [nRx × Pcsirs]
2451	
2452	    % SVD → leading nLayers right singular vectors as target beams
2453	    [~, ~, V] = svd(H_wb, 'econ');
2454	    V_svd = V(:, 1:nLayers);   % [Pcsirs × nLayers]
2455	    % Both halves: vlm part (upper) + co-phased copy (lower)
2456	    V_top = V_svd(1:n_len, :);        % [N1N2 × nLayers]
2457	    V_bot = V_svd(n_len+1:end, :);    % [N1N2 × nLayers]
2458	
2459	    best_cap  = -Inf;
2460	    best_W    = zeros(Pcsirs, nLayers);
2461	    best_pmi  = struct('q1',0,'q2',0,'n_idx',zeros(1,nLayers),'c_idx',zeros(1,nLayers));
2462	
2463	    % --- Stage 1+2: enumerate (q1,q2), greedy per-layer beam selection ---
2464	    for q_idx = 0:q_len-1
2465	        q1 = floor(q_idx / O2);
2466	        q2 = mod(q_idx, O2);
2467	
2468	        % Build DFT matrix V_q: [N1N2 × N1N2], column n = vlm for beam n
2469	        V_q = zeros(n_len, n_len);
2470	        for n_idx = 0:n_len-1
2471	            n_val = N1*N2 - 1 - n_idx;
2472	            n1    = mod(n_val, N1);
2473	            n2    = (n_val - n1) / N1;
2474	            m1    = O1*n1 + q1;
2475	            m2    = O2*n2 + q2;
2476	            V_q(:, n_idx+1) = getVlm(N1, N2, O1, O2, m1, m2);
2477	        end
2478	
2479	        % Beam candidates per layer:
2480	        % rank 1 → exhaustive over all N1*N2 beams (same search space as Mode A)
2481	        % rank > 1 → greedy top-1 per layer using both-polarisation SVD scores
2482	        if nLayers == 1
2483	            % [n_len × 1]: each row is a 1-beam candidate (0-based index)
2484	            n_cand_matrix = (0:n_len-1)';
2485	        else
2486	            scores = abs(V_q' * V_top).^2 + abs(V_q' * V_bot).^2; % [n_len × nLayers]
2487	            n_cand = zeros(1, nLayers);
2488	            for l = 1:nLayers
2489	                [~, n_cand(l)] = max(scores(:, l));
2490	                n_cand(l) = n_cand(l) - 1;   % 0-based
2491	            end
2492	            n_cand_matrix = n_cand;  % [1 × nLayers]: single combination to try
2493	        end
2494	
2495	        % Co-phase combinations: 4^nLayers entries
2496	        c_combos = dec2base(0:4^nLayers-1, 4, nLayers) - '0';  % [4^v × v]
2497	
2498	        for n_row = 1:size(n_cand_matrix, 1)
2499	            if nLayers == 1
2500	                n_try = n_cand_matrix(n_row);   % scalar, 0-based
2501	            else
2502	                n_try = n_cand_matrix(n_row, :); % [1 × nLayers], 0-based
2503	            end
2504	
2505	            for ci = 1:size(c_combos, 1)
2506	                c_vec = c_combos(ci, :);  % [1 × nLayers]
2507	
2508	                % Assemble W per Table 5.2.2.2.1a-7
2509	                W_top_c = zeros(n_len, nLayers);
2510	                W_bot_c = zeros(n_len, nLayers);
2511	                for l = 1:nLayers
2512	                    nb    = n_try(min(l, numel(n_try)));
2513	                    n_val = N1*N2 - 1 - nb;
2514	                    n1    = mod(n_val, N1);
2515	                    n2    = (n_val - n1) / N1;
2516	                    m1    = O1*n1 + q1;
2517	                    m2    = O2*n2 + q2;
2518	                    v_l   = getVlm(N1, N2, O1, O2, m1, m2);
2519	                    W_top_c(:, l) = v_l;
2520	                    W_bot_c(:, l) = phi(c_vec(l)) * v_l;
2521	                end
2522	                W_cand = (1/sqrt(nLayers * Pcsirs)) * [W_top_c; W_bot_c];
2523	
2524	                % Capacity: log2 det(I + (1/nVar) * H * W * W' * H')
2525	                H_eff = H_wb * W_cand;   % [nRx × nLayers]
2526	                cap   = real(log2(det(eye(size(H_eff,1)) + (1/nVar) * (H_eff * H_eff'))));
2527	
2528	                if cap > best_cap
2529	                    best_cap  = cap;
2530	                    best_W    = W_cand;
2531	                    best_pmi.q1    = q1;
2532	                    best_pmi.q2    = q2;
2533	                    best_pmi.n_idx = n_try(:)';  % row vector, 0-based
2534	                    best_pmi.c_idx = c_vec;
2535	                end
2536	            end
2537	        end
2538	    end
2539	
2540	    % ---- Stage 3: per-subband co-phase optimisation -------------------------
2541	    % The wideband beam (q1,q2,n_idx) is fixed; only the co-phase c_l per
2542	    % layer is re-selected independently for each subband.
2543	    numSubbands  = subbandInfo.NumSubbands;
2544	    best_q1      = best_pmi.q1;
2545	    best_q2      = best_pmi.q2;
2546	    best_n_idx   = best_pmi.n_idx;   % [1 × nLayers], 0-based
2547	
2548	    % Pre-build wideband beam vectors for each layer (fixed for all subbands)
2549	    vl_beams = zeros(n_len, nLayers);   % [N1N2 × nLayers]
2550	    for l = 1:nLayers
2551	        nb    = best_n_idx(min(l, numel(best_n_idx)));
2552	        n_val = N1*N2 - 1 - nb;
2553	        n1    = mod(n_val, N1);
2554	        n2    = (n_val - n1) / N1;
2555	        m1    = O1*n1 + best_q1;
2556	        m2    = O2*n2 + best_q2;
2557	        vl_beams(:,l) = getVlm(N1, N2, O1, O2, m1, m2);
2558	    end
2559	
2560	    c_combos_sb  = dec2base(0:4^nLayers-1, 4, nLayers) - '0';  % [4^v × v]
2561	    c_idx_sb     = zeros(nLayers, numSubbands);   % 0-based co-phase per subband
2562	    W_sb_all     = zeros(Pcsirs, nLayers, numSubbands);
2563	    sinrOut      = zeros(numSubbands, nLayers);
2564	    subbandStart = 0;
2565	
2566	    for sb = 1:numSubbands
2567	        sbMask = (csirsIndBWP_k > subbandStart*12) & ...
2568	                 (csirsIndBWP_k < (subbandStart + subbandInfo.SubbandSizes(sb))*12 + 1);
2569	        sbIdx = find(sbMask);
2570	        if isempty(sbIdx)
2571	            % No CSI-RS in this subband — carry over wideband co-phase
2572	            c_idx_sb(:,sb) = best_pmi.c_idx(:);
2573	            W_sb_all(:,:,sb) = best_W;
2574	        else
2575	            H_sb = mean(Hcsirs(:,:,sbIdx), 3);   % [nRx × Pcsirs]
2576	            best_cap_sb = -Inf;
2577	            best_c_sb   = best_pmi.c_idx(:);
2578	            for ci = 1:size(c_combos_sb, 1)
2579	                c_vec = c_combos_sb(ci,:);
2580	                W_top = zeros(n_len, nLayers);
2581	                W_bot = zeros(n_len, nLayers);
2582	                for l = 1:nLayers
2583	                    W_top(:,l) = vl_beams(:,l);
2584	                    W_bot(:,l) = phi(c_vec(l)) * vl_beams(:,l);
2585	                end
2586	                W_c   = (1/sqrt(nLayers*Pcsirs)) * [W_top; W_bot];
2587	                H_eff = H_sb * W_c;
2588	                cap   = real(log2(det(eye(size(H_eff,1)) + (1/nVar) * (H_eff*H_eff'))));
2589	                if cap > best_cap_sb
2590	                    best_cap_sb = cap;
2591	                    best_c_sb   = c_vec(:);
2592	                end
2593	            end
2594	            c_idx_sb(:,sb) = best_c_sb;
2595	            % Assemble final precoder for this subband
2596	            W_top = zeros(n_len, nLayers);
2597	            W_bot = zeros(n_len, nLayers);
2598	            for l = 1:nLayers
2599	                W_top(:,l) = vl_beams(:,l);
2600	                W_bot(:,l) = phi(best_c_sb(l)) * vl_beams(:,l);
2601	            end
2602	            W_sb_all(:,:,sb) = (1/sqrt(nLayers*Pcsirs)) * [W_top; W_bot];
2603	            % Per-subband ZF SINR
2604	            H_eff = H_sb * W_sb_all(:,:,sb);
2605	            W_zf  = pinv(H_eff);
2606	            for l = 1:nLayers
2607	                sig  = abs(W_zf(l,:) * H_eff(:,l))^2;
2608	                intf = sum(abs(W_zf(l,:) * H_eff).^2) - sig;
2609	                sinrOut(sb,l) = sig / (intf + nVar * norm(W_zf(l,:))^2);
2610	            end
2611	        end
2612	        subbandStart = subbandStart + subbandInfo.SubbandSizes(sb);
2613	    end
2614	
2615	    W               = W_sb_all;           % [Pcsirs × nLayers × numSubbands]
2616	    pmiModeB        = best_pmi;
2617	    pmiModeB.c_idx_sb = c_idx_sb;         % [nLayers × numSubbands], 0-based
2618	end
