2620	function vlm = getVlm(N1,N2,O1,O2,l,m)
2621	%   vlm = getVlm(N1,N2,O1,O2,l,m) computes vlm vector according to
2622	%   TS 38.214 Section 5.2.2.2.1 considering the panel configuration
2623	%   [N1, N2], DFT oversampling factors [O1, O2], and vlm indices l and m.
2624	
2625	    um = exp(2*pi*1i*m*(0:N2-1)/(O2*N2));
2626	    ul = exp(2*pi*1i*l*(0:N1-1)/(O1*N1)).';
2627	    vlm =  reshape((ul.*um).',[],1);
2628	end
2629	
2630	function vbarlm = getVbarlm(N1,N2,O1,O2,l,m)
2631	%   vbarlm = getVbarlm(N1,N2,O1,O2,l,m) computes vbarlm vector according to
2632	%   TS 38.214 Section 5.2.2.2.1 considering the panel configuration
2633	%   [N1, N2], DFT oversampling factors [O1, O2], and vbarlm indices l and m.
2634	
2635	    % Calculate vbarlm (DFT vector required to compute the precoding matrix)
2636	    um = exp(2*pi*1i*m*(0:N2-1)/(O2*N2));
2637	    ul = exp(2*pi*1i*l*(0:(N1/2)-1)/(O1*N1/2)).';
2638	    vbarlm = reshape((ul.*um).',[],1);
2639	end
