2641	function [vlmRestricted,i2Restricted] = isRestricted(codebookSubsetRestriction,bitIndex,n,i2Restriction)
2642	%   [VLMRESTRICTED,I2RESTRICTED] = isRestricted(CODEBOOKSUBSETRESTRICTION,BITINDEX,N,I2RESTRICTION)
2643	%   returns the status of vlm or vbarlm restriction and i2 restriction for
2644	%   a codebook index set, as defined in TS 38.214 Section 5.2.2.2.1 by
2645	%   considering these inputs:
2646	%
2647	%   CODEBOOKSUBSETRESTRICTION - Binary vector for vlm or vbarlm restriction
2648	%   BITINDEX                  - Bit index or indices (0-based) associated
2649	%                               with all the precoding matrices based on
2650	%                               vlm or vbarlm
2651	%   N                         - Co-phasing factor index
2652	%   I2RESTRICTION             - Binary vector for i2 restriction
2653	
2654	    % Get the restricted index positions from the codebookSubsetRestriction
2655	    % binary vector
2656	    restrictedIdx = reshape(find(~codebookSubsetRestriction)-1,1,[]);
2657	    vlmRestricted = false;
2658	    if any(sum(restrictedIdx == bitIndex(:),2))
2659	        vlmRestricted = true;
2660	    end
2661	
2662	    restrictedi2List = find(~i2Restriction)-1;
2663	    i2Restricted = false;
2664	    % Update the i2Restricted flag, if the precoding matrices based on vlm
2665	    % or vbarlm are restricted
2666	    if any(restrictedi2List == n)
2667	        i2Restricted = true;
2668	    end
2669	end
