2671	function [i14P] = quantizeAmplitudesP1Rel15(amplitudeVals,maxAllowableAmp)
2672	% i14P = quantizeAmplitudesP1Rel15(AMPLITUDEVALS,MAXALLOWABLEAMP) returns
2673	% the amplitude index i14P value for the given amplitude value
2674	% AMPLITUDEVALS, rounded off to the standard defined wideband amplitudes
2675	% for type II codebooks considering the maximum allowable amplitude
2676	% MAXALLOWBLEAMP, defined from codebook subset restriction
2677	
2678	    stdAmps = [0 0.125 0.1768 0.25 0.3536 0.5 0.7071 1];
2679	    allowedAmps = stdAmps(1:find(stdAmps == maxAllowableAmp));
2680	    if isscalar(allowedAmps) % Possible amplitude is zero only
2681	        i14P = 0;
2682	    else
2683	        logStdAmps = log(allowedAmps);
2684	        logStdAmps(1) = 2*logStdAmps(2) - logStdAmps(3);
2685	        [~,idx] = min(abs(log(amplitudeVals) - logStdAmps));
2686	        i14P = allowedAmps(idx);
2687	    end
2688	end
