2690	function i14K = mapPToKVals(amplitudes)
2691	% i14K = mapPToKvals(AMPLITUDES) returns the amplitude indices i14K for the
2692	% given standard defined amplitude values AMPLITUDES mapped to the wideband
2693	% amplitudes as defined in TS 38.214 Table 5.2.2.2.3-2 for type II
2694	% codebooks
2695	
2696	    stdAmps = [0 0.125 0.1768 0.25 0.3536 0.5 0.7071 1];
2697	    i14K = ones(size(amplitudes));
2698	    for ii = 1:numel(amplitudes)
2699	        idx = find(stdAmps == amplitudes(ii));
2700	        i14K(ii) = idx;
2701	    end
2702	
2703	end
